+async fn rpc_dispatch_session_switch_event(manager: Option<ExtensionManager>, payload: Value) {
+    let Some(manager) = manager else {
+        return;
+    };
+
+    let _ = manager
+        .dispatch_event(ExtensionEventName::SessionSwitch, Some(payload))
+        .await;
+}
